1	//! Shared band-table renderer for tick-valued histograms.
2	//!
3	//! [`TProbe`] (scope API, records → drain) stores hardware tick
4	//! deltas and wants a consistent band-table output shape —
5	//! min/p1/…/p99/max rows with first/last/range/count/mean
6	//! columns, plus summary lines for mean, stdev, mean min-p99,
7	//! stdev min-p99. This module provides the implementation.
8	//!
9	//! (Upstream `iiac-perf` also has a `TProbe` fast-path/direct-
10	//! histogram variant that shares this renderer; `tprobe` here
11	//! only vendored the scope-API probe.)
12	//!
13	//! Display unit is chosen by `as_ticks`: `false` converts stored
14	//! tick values to nanoseconds via [`crate::ticks::ticks_per_ns`];
15	//! `true` shows raw ticks.
16	
17	use hdrhistogram::Histogram;
18	
19	use crate::fmt::{fmt_commas, fmt_commas_f64};
20	use crate::ticks;
21	
22	const BOUNDARY_PCTS: &[f64] = &[
23	    0.0, 0.01, 0.10, 0.20, 0.30, 0.40, 0.50, 0.60, 0.70, 0.80, 0.90, 0.99, 1.0,
24	];
25	const BOUNDARY_NAMES: &[&str] = &[
26	    "min", "p1", "p10", "p20", "p30", "p40", "p50", "p60", "p70", "p80", "p90", "p99", "max",
27	];
28	
29	/// Render a band-table report for `hist`, interpreting stored
30	/// values as hardware ticks. `kind` is the header label
31	/// (e.g. `"tprobe"`) and `name` is the probe's name.
32	/// `as_ticks=false` converts to ns; `true` keeps raw ticks.
33	pub(crate) fn render(kind: &str, name: &str, hist: &Histogram<u64>, as_ticks: bool) {
34	    let sample_count = hist.len();
35	    println!("  {kind}: {name} [count={}]", fmt_commas(sample_count));
36	    if sample_count == 0 {
37	        println!();
38	        return;
39	    }
40	
41	    let unit = if as_ticks { "tk" } else { "ns" };
42	    let tpn = ticks::ticks_per_ns();
43	    let conv = |v: u64| -> f64 { if as_ticks { v as f64 } else { v as f64 / tpn } };
44	    let conv_f = |v: f64| -> f64 { if as_ticks { v } else { v / tpn } };
45	
46	    let n_bands = BOUNDARY_PCTS.len() - 1;
47	    let mut band_first = vec![u64::MAX; n_bands];
48	    let mut band_last = vec![0u64; n_bands];
49	    let mut band_count = vec![0u64; n_bands];
50	    let mut band_sum = vec![0u128; n_bands];
51	
52	    let mut cumulative = 0u64;
53	    for iv in hist.iter_recorded() {
54	        let value = iv.value_iterated_to();
55	        let count = iv.count_at_value();
56	        let mid_rank = (cumulative as f64 + count as f64 / 2.0) / sample_count as f64;
57	        let idx = BOUNDARY_PCTS[1..]
58	            .iter()
59	            .position(|&b| mid_rank < b)
60	            .unwrap_or(n_bands - 1); // OK: mid_rank in [0,1]; last boundary is 1.0 so position() only misses at the exact upper edge, which maps to the last band
61	        band_first[idx] = band_first[idx].min(value);
62	        band_last[idx] = band_last[idx].max(value);
63	        band_count[idx] += count;
64	        band_sum[idx] += value as u128 * count as u128;
65	        cumulative += count;
66	    }
67	
68	    struct BandRow {
69	        label: String,
70	        first: String,
71	        last: String,
72	        range: String,
73	        count: String,
74	        mean: String,
75	    }
76	
77	    let mut rows: Vec<BandRow> = Vec::new();
78	    for i in 0..n_bands {
79	        let count = band_count[i];
80	        let (first_v, last_v, range_v, mean_v) = if count == 0 {
81	            (0.0, 0.0, 0.0, 0.0)
82	        } else {
83	            let mean_val = band_sum[i] as f64 / count as f64;
84	            let range_raw = band_last[i] - band_first[i] + 1;
85	            (
86	                conv(band_first[i]),
87	                conv(band_last[i]),
88	                conv(range_raw),
89	                conv_f(mean_val),
90	            )
91	        };
92	        rows.push(BandRow {
93	            label: format!("{}-{}", BOUNDARY_NAMES[i], BOUNDARY_NAMES[i + 1]),
94	            first: fmt_commas_f64(first_v, 0),
95	            last: fmt_commas_f64(last_v, 0),
96	            range: fmt_commas_f64(range_v, 0),
97	            count: fmt_commas(count),
98	            mean: fmt_commas_f64(mean_v, 0),
99	        });
100	    }
101	
102	    let label_w = rows
103	        .iter()
104	        .map(|r| r.label.len())
105	        .max()
106	        .unwrap_or(0) // OK: rows always contains n_bands=12 entries after the loop above
107	        .max("stdev min-p99".len());
108	    let first_w = rows.iter().map(|r| r.first.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
109	    let last_w = rows.iter().map(|r| r.last.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
110	    let range_w = rows.iter().map(|r| r.range.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
111	    let count_w = rows.iter().map(|r| r.count.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
112	    let mean_w = rows.iter().map(|r| r.mean.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
113	
114	    const INDENT: &str = "    ";
115	    const GAP: &str = "    ";
116	
117	    let first_col = INDENT.len() + label_w + 1 + first_w;
118	    let unit_len = 1 + unit.len();
119	    let last_gap = unit_len + GAP.len() + last_w;
120	    let range_gap = unit_len + GAP.len() + range_w;
121	    let count_gap = unit_len + GAP.len() + count_w;
122	    let mean_gap = GAP.len() + mean_w;
123	    println!(
124	        "{:>first_col$}{:>last_gap$}{:>range_gap$}{:>count_gap$}{:>mean_gap$}",
125	        "first", "last", "range", "count", "mean",
126	    );
127	
128	    for r in &rows {
129	        println!(
130	            "{INDENT}{:<label_w$} {:>first_w$} {unit}{GAP}{:>last_w$} {unit}{GAP}{:>range_w$} {unit}{GAP}{:>count_w$}{GAP}{:>mean_w$} {unit}",
131	            r.label, r.first, r.last, r.range, r.count, r.mean,
132	        );
133	    }
134	
135	    let hist_mean = hist.mean();
136	    let skip = first_w
137	        + unit_len
138	        + GAP.len()
139	        + last_w
140	        + unit_len
141	        + GAP.len()
142	        + range_w
143	        + unit_len
144	        + GAP.len()
145	        + count_w;
146	    println!(
147	        "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
148	        "mean",
149	        "",
150	        fmt_commas_f64(conv_f(hist_mean), 0),
151	    );
152	    println!(
153	        "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
154	        "stdev",
155	        "",
156	        fmt_commas_f64(conv_f(hist.stdev()), 0),
157	    );
158	
159	    let trim_count: u64 = band_count[..n_bands - 1].iter().sum();
160	    if trim_count > 0 {
161	        let trim_sum: u128 = band_sum[..n_bands - 1].iter().sum();
162	        let trim_mean = trim_sum as f64 / trim_count as f64;
163	
164	        let mut trim_var_sum = 0.0f64;
165	        let mut trim_var_count = 0u64;
166	        let mut cum = 0u64;
167	        for iv in hist.iter_recorded() {
168	            let value = iv.value_iterated_to();
169	            let count = iv.count_at_value();
170	            let mid_rank = (cum as f64 + count as f64 / 2.0) / sample_count as f64;
171	            let idx = BOUNDARY_PCTS[1..]
172	                .iter()
173	                .position(|&b| mid_rank < b)
174	                .unwrap_or(n_bands - 1); // OK: mid_rank in [0,1]; same reasoning as above
175	            if idx < n_bands - 1 {
176	                let diff = value as f64 - trim_mean;
177	                trim_var_sum += diff * diff * count as f64;
178	                trim_var_count += count;
179	            }
180	            cum += count;
181	        }
182	        let trim_stdev = if trim_var_count > 1 {
183	            (trim_var_sum / trim_var_count as f64).sqrt()
184	        } else {
185	            0.0
186	        };
187	
188	        println!(
189	            "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
190	            "mean min-p99",
191	            "",
192	            fmt_commas_f64(conv_f(trim_mean), 0),
193	        );
194	        println!(
195	            "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}",
196	            "stdev min-p99",
197	            "",
198	            fmt_commas_f64(conv_f(trim_stdev), 0),
199	        );
200	    }
201	    println!();
202	}
