1	//! Scope-based measurement probe: a named, single-writer
2	//! histogram plus a record buffer, populated via `start` /
3	//! `end` (or `end_batch`) rather than `record(ticks)`.
4	//!
5	//! `start(site_id)` reads the hardware tick counter and returns
6	//! an opaque [`TProbeRecId`] carrying `(site_id, start_tsc)`;
7	//! `end(id)` reads the tick counter again and appends a complete
8	//! `(site_id, start_tsc, end_tsc, batch=1)` record to the probe's
9	//! internal buffer. [`TProbe::end_batch`] is the same but records
10	//! a caller-supplied batch size `n`, which [`TProbe::report`]
11	//! uses to divide the scope's tick delta back down to a per-event
12	//! cost before histogram ingestion. No delta math, histogram
13	//! ingestion, or tick→ns conversion happens on the hot path.
14	//!
15	//! This primitive preserves record-order information across
16	//! interleaved scopes and sites (non-stack nesting is supported
17	//! by construction) and gives future evolution space for per-site
18	//! grouping, bounded buffers, background drain threads, and
19	//! long-term trace retention.
20	//!
21	//! Divergences from the `iiac-perf` original that this file was
22	//! vendored from:
23	//! - [`Record`] gained a `batch: u64` field.
24	//! - [`TProbe::end_batch`] added — scope covers `n` events,
25	//!   histogram stores per-event cost.
26	//! - [`TProbe::clear`] added — resets records and histogram,
27	//!   used at the warmup→measurement boundary.
28	//! - [`TProbe::report`] now takes an optional [`Overhead`]
29	//!   and subtracts the per-event framing correction from each
30	//!   stored value at drain time.
31	
32	use hdrhistogram::Histogram;
33	
34	use crate::band_table;
35	use crate::overhead::Overhead;
36	use crate::ticks;
37	
38	/// Opaque handle returned by [`TProbe::start`], consumed by
39	/// [`TProbe::end`] or [`TProbe::end_batch`]. Carries the
40	/// caller-supplied `site_id` and the start-time tick reading;
41	/// no probe-internal allocation happens at `start` time.
42	///
43	/// `#[must_use]` — dropping the id without passing it to `end*`
44	/// leaks the scope (no record is appended).
45	#[must_use]
46	#[derive(Clone, Copy, Debug)]
47	pub struct TProbeRecId {
48	    site_id: u64,
49	    start_tsc: u64,
50	}
51	
52	/// A complete scope record: `(site_id, start_tsc, end_tsc, batch)`.
53	/// Appended at `end*` time; the record buffer only ever holds
54	/// complete records. Drained into the histogram at
55	/// [`TProbe::report`] time, dividing `end_tsc − start_tsc` by
56	/// `batch` so histogram values are always per-event costs.
57	#[derive(Clone, Copy, Debug)]
58	struct Record {
59	    #[allow(dead_code)] // read once per-site grouping lands.
60	    site_id: u64,
61	    start_tsc: u64,
62	    end_tsc: u64,
63	    batch: u64,
64	}
65	
66	/// A named, single-writer histogram of hardware tick-counter
67	/// deltas plus a scope-record buffer. Not `Sync`; cross-thread
68	/// *sharing* is out of scope. `Send` so probes can be moved
69	/// between threads (e.g. returned via a `JoinHandle<TProbe>`
70	/// on shutdown).
71	pub struct TProbe {
72	    name: String,
73	    hist: Histogram<u64>,
74	    records: Vec<Record>,
75	}
76	
77	impl TProbe {
78	    /// Create an empty probe. Histogram upper bound is 1e12
79	    /// ticks (~250 s at 4 GHz, ~100 s at 10 GHz), 3 significant
80	    /// figures.
81	    ///
82	    /// Exits the process (code 1) if the hardware tick counter
83	    /// isn't usable — see [`crate::ticks::require_ok`].
84	    pub fn new(name: &str) -> Self {
85	        ticks::require_ok();
86	        let _ = ticks::ticks_per_ns();
87	        Self {
88	            name: name.to_string(),
89	            hist: Histogram::<u64>::new_with_bounds(1, 1_000_000_000_000, 3).unwrap(), // OK: bounds are constant and valid (1 ≤ low < high, sigfigs in [0,5])
90	            records: Vec::new(),
91	        }
92	    }
93	
94	    /// Begin a scope. Reads the hardware tick counter and
95	    /// returns an opaque [`TProbeRecId`] carrying `(site_id,
96	    /// start_tsc)`. The id must eventually be passed to
97	    /// [`TProbe::end`] or [`TProbe::end_batch`]; a dropped id
98	    /// leaves no record.
99	    #[inline]
100	    pub fn start(&mut self, site_id: u64) -> TProbeRecId {
101	        TProbeRecId {
102	            site_id,
103	            start_tsc: ticks::read_ticks(),
104	        }
105	    }
106	
107	    /// End a single-event scope (batch = 1). Reads the hardware
108	    /// tick counter and appends a complete record. Delta and
109	    /// histogram ingestion are deferred to [`TProbe::report`].
110	    #[inline]
111	    pub fn end(&mut self, tpri: TProbeRecId) {
112	        let end_tsc = ticks::read_ticks();
113	        self.records.push(Record {
114	            site_id: tpri.site_id,
115	            start_tsc: tpri.start_tsc,
116	            end_tsc,
117	            batch: 1,
118	        });
119	    }
120	
121	    /// End a batched scope covering `n` events. The histogram
122	    /// stores `(end − start) / n` at [`Self::report`] time so
123	    /// per-event cost is what gets rendered, regardless of batch
124	    /// size. Larger batches amortize probe apparatus overhead
125	    /// and push stored tick values into a range where the
126	    /// histogram's 0.1 %-relative buckets actually resolve small
127	    /// variations.
128	    #[inline]
129	    pub fn end_batch(&mut self, tpri: TProbeRecId, n: u64) {
130	        let end_tsc = ticks::read_ticks();
131	        self.records.push(Record {
132	            site_id: tpri.site_id,
133	            start_tsc: tpri.start_tsc,
134	            end_tsc,
135	            batch: n,
136	        });
137	    }
138	
139	    /// Discard all pending records and zero the histogram. Used
140	    /// at the warmup → measurement boundary so only steady-state
141	    /// data reaches the report.
142	    pub fn clear(&mut self) {
143	        self.records.clear();
144	        self.hist.reset();
145	    }
146	
147	    /// Render a band-table report for this probe. `as_ticks`
148	    /// controls the display unit: `false` converts stored tick
149	    /// deltas to nanoseconds (default for the CLI); `true` shows
150	    /// raw ticks (`-t`/`--ticks`). `overhead` (if `Some`)
151	    /// subtracts per-event framing correction from each drained
152	    /// record.
153	    ///
154	    /// Drains any pending `start` / `end*` records into the
155	    /// histogram before rendering:
156	    /// `per_event = (end_tsc − start_tsc) / batch - overhead_correction`,
157	    /// clamped to `1` since the histogram lower bound is 1.
158	    pub fn report(&mut self, as_ticks: bool, overhead: Option<&Overhead>) {
159	        for r in self.records.drain(..) {
160	            let delta = r.end_tsc.saturating_sub(r.start_tsc);
161	            let batch = r.batch.max(1);
162	            let per_event_raw = (delta + batch / 2) / batch;
163	            let per_event = if let Some(ovh) = overhead {
164	                per_event_raw.saturating_sub(ovh.per_event_ticks(batch))
165	            } else {
166	                per_event_raw
167	            };
168	            self.hist.record(per_event.max(1)).unwrap(); // OK: histogram bounds are [1, 1e12]; per_event.max(1) ≥ 1, and per-event tick deltas stay well under 1e12
169	        }
170	        band_table::render("tprobe", &self.name, &self.hist, as_ticks);
171	    }
172	}
