1	//! Runtimes that drive [`Actor`]s. Two flavors live here:
2	//! [`SingleThreadRuntime`] (Goal1: one thread, FIFO queue) and
3	//! [`MultiThreadRuntime`] (Goal2: one thread per actor, `mpsc`
4	//! channels).
5	
6	use std::collections::VecDeque;
7	use std::sync::mpsc::{self, Receiver, Sender};
8	use std::thread::{self, JoinHandle};
9	use std::time::{Duration, Instant};
10	
11	use crate::{Actor, Context, Message};
12	use tprobe::TProbe;
13	
14	/// Single-threaded runtime: all actors run on the calling thread,
15	/// sharing one FIFO message queue. Dispatch loops until either the
16	/// caller-supplied deadline expires or the queue drains.
17	///
18	/// Dispatch is wrapped in a [`TProbe`] batched scope covering
19	/// `inner` consecutive `handle_message` calls; per-event latency
20	/// is available via [`Self::probe_mut`] after [`Self::run_for`]
21	/// returns. The scope's `site_id` is the first `dst_id` in the
22	/// batch (arbitrary-but-stable when `inner > 1`).
23	pub struct SingleThreadRuntime {
24	    actors: Vec<Box<dyn Actor>>,
25	    queue: VecDeque<(u32, Message)>,
26	    probe: TProbe,
27	}
28	
29	impl SingleThreadRuntime {
30	    /// Create an empty runtime with no actors or pending messages.
31	    /// `probe_name` names the embedded probe in its band-table
32	    /// report (e.g. `"goal1.dispatch"`).
33	    pub fn new(probe_name: &str) -> Self {
34	        Self {
35	            actors: Vec::new(),
36	            queue: VecDeque::new(),
37	            probe: TProbe::new(probe_name),
38	        }
39	    }
40	
41	    /// Register `actor`; the returned `u32` is its stable id for
42	    /// the lifetime of the runtime and is usable as `dst_id` in
43	    /// [`Context::send`]. Ids are allocated sequentially from 0.
44	    pub fn add_actor(&mut self, actor: Box<dyn Actor>) -> u32 {
45	        let id = self.actors.len() as u32;
46	        self.actors.push(actor);
47	        id
48	    }
49	
50	    /// Enqueue an initial message for `dst_id`. Used to prime the
51	    /// dispatch loop before [`Self::run_for`].
52	    pub fn seed(&mut self, dst_id: u32, msg: Message) {
53	        self.queue.push_back((dst_id, msg));
54	    }
55	
56	    /// Dispatch messages until `duration` elapses or the queue
57	    /// empties. Each probe scope wraps `inner` consecutive
58	    /// dispatches. A partial trailing batch (queue emptied
59	    /// mid-scope) is discarded — neither recorded nor counted —
60	    /// so throughput numbers reflect whole-batch work only.
61	    ///
62	    /// Returns the total number of messages counted toward
63	    /// whole batches.
64	    pub fn run_for(&mut self, duration: Duration, inner: u64) -> u64 {
65	        let deadline = Instant::now() + duration;
66	        let mut count = 0u64;
67	        while Instant::now() < deadline {
68	            let first_dst = match self.queue.front() {
69	                Some((d, _)) => *d,
70	                None => break,
71	            };
72	            let Self {
73	                actors,
74	                queue,
75	                probe,
76	            } = self;
77	            let id = probe.start(first_dst as u64);
78	            let mut done: u64 = 0;
79	            while done < inner {
80	                let Some((dst, msg)) = queue.pop_front() else {
81	                    break;
82	                };
83	                let actor = &mut actors[dst as usize];
84	                let mut ctx = SingleCtx { queue };
85	                actor.handle_message(&mut ctx, msg);
86	                done += 1;
87	            }
88	            if done == inner {
89	                probe.end_batch(id, inner);
90	                count += done;
91	            } else {
92	                // Partial trailing batch: drop the scope (don't
93	                // record or count) and stop.
94	                break;
95	            }
96	        }
97	        count
98	    }
99	
100	    /// Mutable access to the embedded probe — used by callers to
101	    /// invoke [`TProbe::clear`] at the warmup → measurement
102	    /// boundary and [`TProbe::report`] after [`Self::run_for`]
103	    /// returns.
104	    pub fn probe_mut(&mut self) -> &mut TProbe {
105	        &mut self.probe
106	    }
107	}
108	
109	/// [`Context`] impl used by [`SingleThreadRuntime`]: pushes onto
110	/// the runtime's shared queue.
111	struct SingleCtx<'a> {
112	    queue: &'a mut VecDeque<(u32, Message)>,
113	}
114	
115	impl Context for SingleCtx<'_> {
116	    /// Push `(dst_id, msg)` onto the shared dispatch queue.
117	    fn send(&mut self, dst_id: u32, msg: Message) {
118	        self.queue.push_back((dst_id, msg));
119	    }
120	}
121	
122	#[cfg(test)]
123	mod tests {
124	    use super::*;
125	
126	    /// Minimal actor that drops every message without replying.
127	    struct Sink;
128	
129	    impl Actor for Sink {
130	        fn handle_message(&mut self, _ctx: &mut dyn Context, _msg: Message) {}
131	    }
132	
133	    /// Bounded ping-pong actor: replies to its peer up to `max`
134	    /// times, then goes silent. Used to produce a deterministic
135	    /// message count in unit tests without wall-clock dependence.
136	    struct Bouncer {
137	        peer: u32,
138	        sent: u32,
139	        max: u32,
140	    }
141	
142	    impl Actor for Bouncer {
143	        fn handle_message(&mut self, ctx: &mut dyn Context, _msg: Message) {
144	            if self.sent < self.max {
145	                ctx.send(self.peer, Message);
146	                self.sent += 1;
147	            }
148	        }
149	    }
150	
151	    #[test]
152	    fn seed_is_handled_and_queue_drains() {
153	        let mut rt = SingleThreadRuntime::new("test.drain");
154	        let id = rt.add_actor(Box::new(Sink));
155	        rt.seed(id, Message);
156	        let n = rt.run_for(Duration::from_millis(1), 1);
157	        assert_eq!(n, 1);
158	    }
159	
160	    #[test]
161	    fn bounded_ping_pong_count() {
162	        let mut rt = SingleThreadRuntime::new("test.bounded");
163	        let a = rt.add_actor(Box::new(Bouncer {
164	            peer: 1,
165	            sent: 0,
166	            max: 5,
167	        }));
168	        let _b = rt.add_actor(Box::new(Bouncer {
169	            peer: 0,
170	            sent: 0,
171	            max: 5,
172	        }));
173	        rt.seed(a, Message);
174	        // seed (1) + 5 from a + 5 from b = 11, all whole batches at inner=1.
175	        let n = rt.run_for(Duration::from_secs(1), 1);
176	        assert_eq!(n, 11);
177	    }
