            "stdev", "", hist_stdev_str,
        );
    }

    if have_trim {
        if show_adj {
            println!(
                "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}{GAP}{:>adj_w$} {unit}",
                "mean min-p99", "", trim_mean_str, trim_mean_adj_str,
            );
            println!(
                "{INDENT}{:<label_w$} {:>skip$}{GAP}{:>mean_w$} {unit}{GAP}{:>adj_cell_w$}",
