mod tests {
    use super::*;

    #[test]
    fn per_event_ticks_amortizes_framing() {
        let ovh = Overhead {
            framing_ticks: 20,
            loop_per_iter_ticks: 0.0,
            cal_raw_low_ticks: 0,
            cal_raw_high_ticks: 0,
            cal_duration: Duration::from_millis(1),
