        assert_eq!(ovh.per_event_ticks(1), 22);
        // batch=10:   2 + 1.5 =  3.5  →  4
        assert_eq!(ovh.per_event_ticks(10), 4);
        // batch=1000: 0.02 + 1.5 = 1.52 →  2
        assert_eq!(ovh.per_event_ticks(1000), 2);
    }

